export type WeftPluginPdas = {
  distributor: typeof findDistributorPda;
  epochDistribution: typeof findEpochDistributionPda;
  claimStatus: typeof findClaimStatusPda;
  position: typeof findPositionPda;
  escrow: typeof findEscrowPda;
  escrowVault: typeof findEscrowVaultPda;
  registry: typeof findRegistryPda;
  node: typeof findNodePda;
  stakingConfig: typeof findStakingConfigPda;
  rewardVault: typeof findRewardVaultPda;
  treeShard: typeof findTreeShardPda;
  vault: typeof findVaultPda;
};

export type WeftPluginRequirements = ClientWithRpc<GetAccountInfoApi & GetMultipleAccountsApi> &
  ClientWithPayer &
  ClientWithTransactionPlanning &
  ClientWithTransactionSending;

export function weftProgram() {
  return <T extends WeftPluginRequirements>(
    client: T,
  ): ExtendedClient<T, { weft: WeftPlugin }> => {
    return extendClient(client, {
      weft: <WeftPlugin>{
        accounts: {
          claimStatus: addSelfFetchFunctions(client, getClaimStatusCodec()),
          distributor: addSelfFetchFunctions(client, getDistributorCodec()),
          epochDistribution: addSelfFetchFunctions(client, getEpochDistributionCodec()),
          nodeState: addSelfFetchFunctions(client, getNodeStateCodec()),
          paymentEscrow: addSelfFetchFunctions(client, getPaymentEscrowCodec()),
          registry: addSelfFetchFunctions(client, getRegistryCodec()),
          stakePosition: addSelfFetchFunctions(client, getStakePositionCodec()),
          stakingConfig: addSelfFetchFunctions(client, getStakingConfigCodec()),
          treeShard: addSelfFetchFunctions(client, getTreeShardCodec()),
        },
        instructions: {
          claim: (input) => addSelfPlanAndSendFunctions(client, getClaimInstructionAsync(input)),
          closeEmptyStakePosition: (input) =>
            addSelfPlanAndSendFunctions(client, getCloseEmptyStakePositionInstructionAsync(input)),
          closeEscrow: (input) =>
            addSelfPlanAndSendFunctions(client, getCloseEscrowInstructionAsync(input)),
          depositEscrow: (input) =>
            addSelfPlanAndSendFunctions(client, getDepositEscrowInstructionAsync(input)),
          deregisterNode: (input) =>
            addSelfPlanAndSendFunctions(client, getDeregisterNodeInstructionAsync(input)),
          dispute: (input) =>
            addSelfPlanAndSendFunctions(client, getDisputeInstructionAsync(input)),
          fundRewardVault: (input) =>
            addSelfPlanAndSendFunctions(client, getFundRewardVaultInstructionAsync(input)),
          initializeCore: (input) =>
            addSelfPlanAndSendFunctions(client, getInitializeCoreInstructionAsync(input)),
          payTraffic: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getPayTrafficInstructionAsync({ ...input, payer: input.payer ?? client.payer }),
            ),
          payTrafficFromEscrow: (input) =>
            addSelfPlanAndSendFunctions(client, getPayTrafficFromEscrowInstructionAsync(input)),
          postEpoch: (input) =>
            addSelfPlanAndSendFunctions(client, getPostEpochInstructionAsync(input)),
          registerNode: (input) =>
            addSelfPlanAndSendFunctions(client, getRegisterNodeInstructionAsync(input)),
          registerTree: (input) =>
            addSelfPlanAndSendFunctions(client, getRegisterTreeInstructionAsync(input)),
          requestUnstake: (input) =>
            addSelfPlanAndSendFunctions(client, getRequestUnstakeInstructionAsync(input)),
          setCoreAuthority: (input) =>
            addSelfPlanAndSendFunctions(client, getSetCoreAuthorityInstructionAsync(input)),
          setDisputeAuthority: (input) =>
            addSelfPlanAndSendFunctions(client, getSetDisputeAuthorityInstructionAsync(input)),
          setPaused: (input) =>
            addSelfPlanAndSendFunctions(client, getSetPausedInstructionAsync(input)),
          setPosterAuthority: (input) =>
            addSelfPlanAndSendFunctions(client, getSetPosterAuthorityInstructionAsync(input)),
          setRegistryCollection: (input) =>
            addSelfPlanAndSendFunctions(client, getSetRegistryCollectionInstructionAsync(input)),
          settleFromEscrow: (input) =>
            addSelfPlanAndSendFunctions(client, getSettleFromEscrowInstructionAsync(input)),
          shutdownCore: (input) =>
            addSelfPlanAndSendFunctions(client, getShutdownCoreInstructionAsync(input)),
          stake: (input) => addSelfPlanAndSendFunctions(client, getStakeInstructionAsync(input)),
          updateNode: (input) =>
            addSelfPlanAndSendFunctions(client, getUpdateNodeInstruction(input)),
          withdrawEscrow: (input) =>
            addSelfPlanAndSendFunctions(client, getWithdrawEscrowInstructionAsync(input)),
          withdrawUnstaked: (input) =>
            addSelfPlanAndSendFunctions(client, getWithdrawUnstakedInstructionAsync(input)),
        },
        pdas: {
          distributor: findDistributorPda,
          epochDistribution: findEpochDistributionPda,
          claimStatus: findClaimStatusPda,
          position: findPositionPda,
          escrow: findEscrowPda,
          escrowVault: findEscrowVaultPda,
          registry: findRegistryPda,
          node: findNodePda,
          stakingConfig: findStakingConfigPda,
          rewardVault: findRewardVaultPda,
          treeShard: findTreeShardPda,
          vault: findVaultPda,
        },
        identifyAccount: identifyWeftAccount,
        identifyInstruction: identifyWeftInstruction,
        parseInstruction: parseWeftInstruction,
      },
    });
  };
}

type MakeOptional<T, K extends keyof T> = Omit<T, K> & Partial<Pick<T, K>>;
